interface Todo {
  id: number;
  title: string;
  description: string;
  completed: boolean;
  createdAt: Date;
  userId: number;
}

// For creating a todo (no id, createdAt, userId)
type CreateTodo = Omit<Todo, "id" | "createdAt" | "userId">;

// For displaying in a list (only essential fields)
type TodoListItem = Pick<Todo, "id" | "title" | "completed">;

// For updating (partial + no system fields)
type UpdateTodo = Partial<Omit<Todo, "id" | "createdAt" | "userId">>;

function createTodo(input: CreateTodo): Todo {
  return {
    ...input,
    id: Date.now(),
    createdAt: new Date(),
    userId: 1
  };
}
